const input = $input.first().json.body || $input.first().json;

if (!input.topic || input.topic.trim() === '') {
  throw new Error('Topic is required. Please provide a topic in the request body.');
}

return [{
  json: {
    topic: input.topic.trim(),
    brief: input.brief || input.topic.trim(),
    brand_voice: input.brand_voice || 'professional and engaging',
    target_audience: input.target_audience || 'general audience',
    timestamp: new Date().toISOString(),
    request_id: 'REQ_' + Date.now()
  }
}];

