const response = $input.first().json;
const original = $('Validate Input').first().json;

if (response.error) {
  throw new Error(typeof response.error === 'string' ? response.error : response.error.message || 'API Error');
}

let text = '';
try {
  text = response.choices[0].message.content || '';
} catch (e) {
  throw new Error('Invalid API response structure');
}

text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : text);
} catch {
  parsed = {
    caption_base: text.substring(0, 400),
    hashtags: ['#AI', '#Automation', '#Business', '#India', '#Tech'],
    cta: 'Contact us today to learn more!',
    image_prompt: 'Professional business automation concept India modern office',
    video_prompt: 'Short video showing AI transforming a small business'
  };
}

const hashtags = Array.isArray(parsed.hashtags) ? parsed.hashtags : ['#AI', '#Automation', '#Business'];

return [{
  json: {
    ...original,
    caption_base: typeof parsed.caption_base === 'string' ? parsed.caption_base : text.substring(0, 400),
    hashtags: hashtags,
    hashtags_string: hashtags.join(' '),
    cta: typeof parsed.cta === 'string' ? parsed.cta : 'Learn more today!',
    image_prompt: typeof parsed.image_prompt === 'string' ? parsed.image_prompt : 'Professional business concept',
    video_prompt: typeof parsed.video_prompt === 'string' ? parsed.video_prompt : ''
  }
}];

return [{
  json: {
    ...$('Parse Gemini Output').first().json,
    image_url: `https://image.pollinations.ai/prompt/${encodeURIComponent($('Parse Gemini Output').first().json.image_prompt)}`,
  }
}];

const data = $input.first().json;
const caption = typeof data.caption_base === 'string' ? data.caption_base : '';
const hashtags = Array.isArray(data.hashtags) ? data.hashtags : [];
const cta = typeof data.cta === 'string' ? data.cta : 'Learn more today!';
const hashtagsStr = hashtags.join(' ');

// Instagram - emoji heavy, all hashtags
const instagramCaption = `${caption}\n\n✨ ${cta}\n\n${hashtagsStr}`;

// LinkedIn - professional, 5 hashtags max
const linkedinHashtags = hashtags.slice(0, 5).join(' ');
const linkedinCaption = `${caption}\n\n${cta}\n\n${linkedinHashtags}`;

// Facebook - conversational, 7 hashtags
const fbHashtags = hashtags.slice(0, 7).join(' ');
const facebookCaption = `${caption}\n\n${cta}\n\n${fbHashtags}`;

// YouTube
const youtubeTitle = data.topic && data.topic.length > 100 ? data.topic.substring(0, 97) + '...' : (data.topic || 'AI Social Media');
const youtubeDescription = `${caption}\n\n${cta}\n\n${hashtagsStr}`;

return [{
  json: {
    ...data,
    instagram_caption: instagramCaption,
    linkedin_caption: linkedinCaption,
    facebook_caption: facebookCaption,
    youtube_title: youtubeTitle,
    youtube_description: youtubeDescription
  }
}];

const platformData = $('Platform-Specific Versions').first().json;

// INSTAGRAM
let instagramStatus = 'SUCCESS';
let instagramPostId = '';
let instagramError = '';
try {
  const ig = $('Instagram - Post via OpenCLI').first().json;
  if (ig.output && ig.output.includes('Posted')) {
    instagramStatus = 'SUCCESS';
    instagramPostId = 'IG_POSTED';
  } else if (ig.error && ig.error.trim() !== '') {
    instagramStatus = 'FAILED';
    instagramError = ig.error;
  }
} catch (e) {
  instagramStatus = 'FAILED';
  instagramError = e.message;
}

// TWITTER
let twitterStatus = 'SUCCESS';
let twitterPostId = '';
let twitterError = '';
try {
  const tw = $('Twitter - Post Tweet').first().json;
  if (tw.output && tw.output.includes('posted successfully')) {
    twitterStatus = 'SUCCESS';
    twitterPostId = 'TW_POSTED';
  } else if (tw.error && tw.error.trim() !== '') {
    twitterStatus = 'FAILED';
    twitterError = tw.error;
  }
} catch (e) {
  twitterStatus = 'FAILED';
  twitterError = e.message;
}

return [{
  json: {
    request_id: platformData.request_id,
    timestamp: platformData.timestamp,
    topic: platformData.topic,
    caption_base: platformData.caption_base,
    hashtags: platformData.hashtags_string,
    cta: platformData.cta,
    image_prompt: platformData.image_prompt,
    image_url: platformData.image_url,
    instagram_caption: platformData.instagram_caption,
    linkedin_caption: platformData.linkedin_caption,
    facebook_caption: platformData.facebook_caption,
    youtube_title: platformData.youtube_title,
    youtube_description: platformData.youtube_description,
    instagram_status: instagramStatus,
    instagram_post_id: instagramPostId,
    instagram_error: instagramError,
    twitter_status: twitterStatus,
    twitter_post_id: twitterPostId,
    twitter_error: twitterError,
    overall_status: instagramStatus === 'SUCCESS' && twitterStatus === 'SUCCESS' ? 'ALL_SUCCESS' : instagramStatus === 'FAILED' && twitterStatus === 'FAILED' ? 'ALL_FAILED' : 'PARTIAL_SUCCESS'
  }
}];

const error = $input.first().json;
const originalInput = $('Validate Input').first()?.json || {};

return [{
  json: {
    request_id: originalInput.request_id || 'ERR_' + Date.now(),
    timestamp: new Date().toISOString(),
    topic: originalInput.topic || 'Unknown',
    error_message: error.message || JSON.stringify(error),
    failed_node: error.node?.name || 'Unknown',
    overall_status: 'WORKFLOW_ERROR'
  }
}];
